import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists(): return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing: existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]: existing[ch][v] = html

ORIGINAL = {
  "1": {
    "1": "<p><strong>vayedaber YHWH el-Moshe bemidbar Sinai be'ohel mo'ed</strong>: 'YHWH spoke to Moses in the wilderness of Sinai, in the tent of meeting.' The book of Numbers opens at the intersection of three theological locations: <em>midbar</em> (wilderness — the in-between place, neither Egypt nor the land), <em>Sinai</em> (the mountain of covenant), and <em>ohel mo'ed</em> (the tent of meeting — the completed tabernacle from which YHWH now speaks, Exod 40:34-35). The divine speech originates from the tabernacle's interior: YHWH who filled the tent with his glory now issues orders from within it. 'The first day of the second month in the second year' places this one month after the tabernacle's completion (Exod 40:17).</p>",
    "2": "<p><strong>seu et rosh</strong>: 'lift the head of' — the Hebrew idiom for conducting a census. <em>Nasa</em> (lift) + <em>rosh</em> (head) = the counting metaphor: each person's head is lifted/registered. The book's Hebrew name <em>Bemidbar</em> (in the wilderness) is preferred over the Greek 'Numbers' (<em>arithmoi</em>) derived from this census. The count proceeds <em>lemishpechotam lebeit avotam</em> (by their clans, by their fathers' houses) — two levels of social organization: <em>mishpacha</em> (extended family/clan) and <em>beit av</em> (father's house, the nuclear family unit). <em>Legulgelotam</em>: by their heads/skulls (from <em>gulgolet</em> = skull; the same root as Golgotha, 'place of the skull').</p>",
    "3": "<p><strong>kol yotzei tzava be-Yisrael</strong>: 'all who go out to war in Israel' — the military framing of the census. <em>Yotzei tzava</em> (those who go out of the host/army) defines the counted group: adult males 20 years and older capable of military service. <em>Tzava</em> (host/army) is also the word behind <em>YHWH tzvaot</em> (LORD of hosts) — the cosmic military title. Israel's earthly army reflects the divine heavenly host. <em>Tifkedu otam le-tzivotam</em>: 'you shall enroll them by their companies/armies' — the corporate military unit (<em>tzava</em>) is the organizing principle.</p>",
    "4": "<p><strong>ve'itchem yihyu ish ish lamatteh</strong>: 'with you shall be a man from each tribe' — one leader per tribe. <em>Ish ish</em> (each man / a man, a man) is the emphatic distributive construction stressing individual responsibility. <em>Matteh</em> (staff/tribe) — the tribe takes its name from the leader's staff; <em>matteh</em> means both 'rod/staff' (the leader's symbol) and 'tribe' (those grouped under that staff). The dual meaning preserves the organic connection between leader and community.</p>",
    "5": "<p><strong>ve'eleh shemot ha-anashim asher ya'amdu itchem</strong>: 'and these are the names of the men who shall assist you.' <em>Ya'amdu</em> (shall stand/assist) — the verb <em>amad</em> (stand) expresses readiness and appointment; standing before someone = serving them. The leader 'stands with' Moses and Aaron in the census-taking. <em>Lir'uven</em> (for Reuben): <strong>Elitzur ben Shedeur</strong> — 'my God is a rock, son of the shedder of light.' The names are theophoric; each leader's name reflects covenant theology.</p>",
    "6": "<p><strong>lishim'on</strong>: for Simeon — <strong>Shelumi'el ben Tzurishaddai</strong>: 'my peace is God, son of the rock of Shaddai.' <em>Shaddai</em> (the Almighty/El Shaddai) appears in the father's name; the Shaddai title, prominent in Genesis, continues through the tribal lineage.</p>",
    "7": "<p><strong>liYhudah</strong>: for Judah — <strong>Nachshon ben Aminadav</strong>: 'serpent (or diver), son of the willing people.' Nachshon ben Aminadav will later be identified in rabbinic tradition as the first to step into the Red Sea. His name appears in the genealogy of David (Ruth 4:20) and in Matthew's genealogy of Jesus (Matt 1:4). The Judahite leader stands in the direct ancestral line of the Messiah.</p>",
    "8": "<p><strong>liYissachar</strong>: for Issachar — <strong>Netanel ben Tzuar</strong>: 'God has given, son of the rock.' The gift-name (<em>natan el</em>) reflects the covenant blessing. Issachar's tribe will later be noted for 'understanding of the times' (1 Chr 12:32).</p>",
    "9": "<p><strong>liZevulun</strong>: for Zebulun — <strong>Eli'av ben Chelon</strong>: 'my God is father, son of strength.' <em>Av</em> (father) in the leader's name reflects the patriarchal theology: God as father of Israel. Zebulun's territory will later encompass the Galilee region where Jesus began his ministry (Matt 4:13-16, citing Isa 9:1-2).</p>",
    "10": "<p><strong>livnei Yosef</strong>: 'for the sons of Joseph' — Joseph's double-tribe inheritance (Ephraim and Manasseh) is listed under his name as the parent tribe. <strong>le-Efrayim: Elishama ben Ammihud</strong>: 'my God has heard, son of my people is glorious.' <strong>liMenashe: Gamliel ben Pedahtzur</strong>: 'God has rewarded, son of redeemed by the rock.' The <em>el</em> (God) and <em>tzur</em> (rock) elements in names continue the creedal pattern.</p>",
    "11": "<p><strong>liBinyamin</strong>: for Benjamin — <strong>Avidan ben Gid'oni</strong>: 'my father is judge, son of my cutter/warrior.' Benjamin's leader is the only one whose father-name references a warrior (<em>gid'on</em> — the same root as the judge Gideon). Benjamin later produces Israel's first king (Saul) and Paul the apostle.</p>",
    "12": "<p><strong>leDan</strong>: for Dan — <strong>Achi'ezer ben Ammishaddai</strong>: 'my brother is help, son of the people of Shaddai.' Dan's leader carries a name of brotherly solidarity (<em>ach</em> = brother; <em>ezer</em> = help). Dan will later become associated with northern apostasy but here stands in covenant solidarity.</p>",
    "13": "<p><strong>le-Asher</strong>: for Asher — <strong>Pag'iel ben Ocheran</strong>: 'God met/encountered me, son of the troubled.' <em>Paga</em> (to meet, encounter, light upon) is a verb with a range from accidental meeting to intentional encounter with God; this leader's name commemorates a divine encounter. The <em>el</em> suffix makes it theophoric.</p>",
    "14": "<p><strong>leGad</strong>: for Gad — <strong>Elyasaf ben Re'u'el</strong>: 'God has added, son of shepherd/friend of God.' <em>Re'u'el</em> is the same name as Jethro's alternate name (Exod 2:18; Num 10:29) — 'friend of God' (<em>re'a el</em>) or possibly 'shepherd of God' (<em>ra'ah el</em>).</p>",
    "15": "<p><strong>leNaftali</strong>: for Naphtali — <strong>Achira ben Enan</strong>: 'my brother is evil/shepherd (?), son of the gracious.' Naphtali, whose territory will also be part of the Galilean region (Isa 9:1), is represented by a leader whose name contains <em>ach</em> (brother) — the fraternal solidarity motif recurring in the tribal leadership roster.</p>",
    "16": "<p><strong>eleh keruyei ha'edah nesiei mattot avotam</strong>: 'these are those called of the congregation, the princes of the tribes of their fathers.' <em>Nesiim</em> (princes) — from <em>nasa</em> (lift); the <em>nasi</em> is the 'lifted one' — lifted above his tribe in honor and responsibility. <em>Mattot avotam</em> (tribes of their fathers) — each <em>nasi</em> represents the patriarchal lineage. The double designation — called of the congregation (<em>keruyei ha'edah</em>) + princes of tribes — marks their dual accountability: elected by the community, representing the ancestral line.</p>",
    "17": "<p><strong>va-yikach Moshe ve-Aharon et ha-anashim ha-eleh asher nikvu beshemot</strong>: 'Moses and Aaron took these men who had been designated by name.' <em>Nikvu beshemot</em> (designated/pierced by names) — <em>naqav</em> (to specify, designate, pierce) applied to naming; to be 'named' in this context is to be officially designated. The names are not incidental; each person is individually identified in the census.</p>",
    "18": "<p><strong>ve-et kol-ha'edah hikehilu be-echad lachodesh hasheni</strong>: 'they assembled all the congregation on the first of the second month.' <em>Hakhel</em> (convene/assemble) — from <em>kahal</em> (assembly, congregation); the census assembles the entire community. <em>Vayityaldu</em> (they declared their genealogies) — <em>yalad</em> (to give birth/genealogize); the census is a genealogical act, rooting each individual in family lineage.</p>",
    "19": "<p><strong>ka'asher tzivah YHWH et Moshe vayifkedem bemidbar Sinai</strong>: 'as YHWH commanded Moses, he enrolled them in the wilderness of Sinai.' The census (<em>paqad</em>) proceeds in exact obedience to divine command. <em>Bemidbar Sinai</em> (in the Sinai wilderness) — the census is wilderness-situated; this is not an enrollment of settled people but of a pilgrim community en route.</p>",
    "20": "<p><strong>vayihyu vnei Reuven bechor Yisrael</strong>: 'the sons of Reuben, the firstborn of Israel.' Reuben is enumerated first as Jacob's eldest. Each tribe's formula begins: <em>ldorotam lemishpechotam lebeit avotam bemispar shemot lgulgelotam</em> — 'by their generations, by their clans, by their fathers' houses, by the number of names, head by head.' The fourfold enumeration structure runs through every tribe: generation, clan, father's house, individual name-count.</p>",
    "21": "<p><strong>peqoudeihem lematteh Reuven shisha ve-arbaim elef vachamesh me'ot</strong>: 'those enrolled of the tribe of Reuben: 46,500.' <em>Pequdim</em> (those enrolled/numbered) from <em>paqad</em>. The number 46,500: <em>elef</em> may mean a military unit rather than a literal thousand in some usages; if so, the figure represents 46 units plus 500 individuals. The tribe numbers across the census are consistent with the total 603,550 in v46.</p>",
    "22": "<p><strong>livnei Shim'on</strong>: for Simeon. The formula repeats for each tribe. Simeon's count (59,300) will decline sharply to 22,200 by the second census (Num 26:14) — the steepest drop of any tribe, likely connected to the Baal Peor incident (Num 25) where the leader Zimri (a Simeonite, Num 25:14) was killed. The census numbers are not static; they reflect covenant consequence.</p>",
    "23": "<p><strong>peqoudeihem lematteh Shim'on tish'ah vachamishim elef ushlosh me'ot</strong>: 'those enrolled of the tribe of Simeon: 59,300.' The <em>paqad</em> formula concludes each tribal count. <em>Tish'ah vachamishim</em> (59) — Simeon's large first-census number will make the second census decline all the more striking.</p>",
    "24": "<p><strong>livnei Gad</strong>: for Gad. Gad, though sixth in Jacob's birth order (son of Zilpah), is enumerated here third after Reuben and Simeon — possibly reflecting the camp assignment (Reuben's group, south camp) rather than strict birth order. The census ordering reflects military-organizational rather than purely genealogical priorities.</p>",
    "25": "<p><strong>peqoudeihem lematteh Gad chamisha vechamishim elef veshesh me'ot vachamishim</strong>: 'those enrolled of the tribe of Gad: 45,650.' Gad's count. <em>Chamishim</em> (fifty) — the round-number components in tribal counts have led some scholars to propose that the census counts represent administrative units, not literal population figures. The debate touches <em>elef</em>'s dual meaning.</p>",
    "26": "<p><strong>livnei Yehudah</strong>: for Judah. Judah leads the eastern camp and will be listed first in the marching order (Num 2:3-9, 10:14). The tribal census sequence here is Reuben, Simeon, Gad (southern camp, Num 2:10-16), then Judah (eastern camp). The census ordering by camp-assignment reflects the military structure of Numbers overall.</p>",
    "27": "<p><strong>peqoudeihem lematteh Yehudah arba'ah veshiv'im elef veshesh me'ot</strong>: 'those enrolled of the tribe of Judah: 74,600' — the largest single tribe. Judah's numerical supremacy reflects the blessing of Jacob (Gen 49:8-12) and Moses (Deut 33:7). From Judah comes the scepter that does not depart (Gen 49:10), the royal line culminating in David and the Messiah.</p>",
    "28": "<p><strong>livnei Yissachar</strong>: for Issachar. Issachar and Zebulun bracket Judah in the eastern camp (Num 2:5-8) — they are Judah's flanking tribes in the vanguard position. Issachar is praised in the Deborah song (Judg 5:15) and later known for wisdom ('understanding the times,' 1 Chr 12:32).</p>",
    "29": "<p><strong>peqoudeihem lematteh Yissachar arba'ah vachamishim elef ve-arba me'ot</strong>: 'those enrolled of the tribe of Issachar: 54,400.' <em>Arba'ah vachamishim</em> (fifty-four). The Issachar count is mid-range among the tribes.</p>",
    "30": "<p><strong>livnei Zevulun</strong>: for Zebulun. Zebulun completes the eastern camp group with Judah and Issachar (Num 2:7). Zebulun is associated with the northern coastal trade region (Gen 49:13) and with the Galilee territory where Jesus ministered (Isa 9:1-2 → Matt 4:13-16).</p>",
    "31": "<p><strong>peqoudeihem lematteh Zevulun shiv'ah vachamishim elef ve-arba me'ot</strong>: 'those enrolled of the tribe of Zebulun: 57,400.' Zebulun's count makes the eastern camp total (Judah + Issachar + Zebulun): 74,600 + 54,400 + 57,400 = 186,400 — the largest camp contingent.</p>",
    "32": "<p><strong>livnei Yosef livnei Efrayim</strong>: 'for the sons of Joseph, for the sons of Ephraim.' Ephraim is listed first of the two Joseph tribes, reflecting Jacob's blessing of Ephraim over Manasseh (Gen 48:14-20: 'the younger shall be greater'). Ephraim becomes the leading tribe of the northern kingdom; the name is sometimes used as a metonym for the northern ten tribes (Isa 7:2; Hos 5:3).</p>",
    "33": "<p><strong>peqoudeihem lematteh Efrayim arba'ah vethlashim elef vachamesh me'ot</strong>: 'those enrolled of the tribe of Ephraim: 40,500.' Ephraim's count (40,500) is smaller than Manasseh's (32,200 is actually... wait, let me check) — actually Manasseh's count will be in v35: 32,200. Ephraim (40,500) is larger, which fits the Jacob blessing precedence. In the second census (Num 26), the numbers reverse — Manasseh becomes larger. The dynamics of blessing and census interact.</p>",
    "34": "<p><strong>livnei Menashe</strong>: for Manasseh. Manasseh, though the elder of Joseph's sons, is listed after Ephraim — reflecting Jacob's cross-handed blessing. The western camp (Num 2:18-24) groups Ephraim, Manasseh, and Benjamin; Ephraim leads this group.</p>",
    "35": "<p><strong>peqoudeihem lematteh Menashe shnayim uthlashim elef umayatayim</strong>: 'those enrolled of the tribe of Manasseh: 32,200.' Manasseh's count is the smallest of the twelve tribes in the first census, despite being Joseph's elder son. The reversal of expected precedence (Manasseh over Ephraim → Ephraim leads) is built into the census itself. By the second census (Num 26:34), Manasseh will overtake Ephraim (52,700 vs. 32,500).</p>",
    "36": "<p><strong>livnei Binyamin</strong>: for Benjamin. Benjamin is the youngest of the twelve sons of Jacob, born last and associated with great loss (Rachel's death, Gen 35:18-19). Benjamin is the only tribe that will remain with Judah after the division (1 Kgs 12:21). Paul identifies himself as Benjamin: 'a Hebrew of Hebrews; as to the law, a Pharisee' (Phil 3:5).</p>",
    "37": "<p><strong>peqoudeihem lematteh Binyamin chamisha uthlashim elef ve-arba me'ot</strong>: 'those enrolled of the tribe of Benjamin: 35,400.' Benjamin's count (35,400) makes the western camp total: 40,500 + 32,200 + 35,400 = 108,100 — the smallest camp contingent, which fits Benjamin's status as the youngest.</p>",
    "38": "<p><strong>livnei Dan</strong>: for Dan. Dan leads the northern camp (Num 2:25-31), which marches last as the 'rear guard.' Dan's position at the rear — the most exposed position — is significant; Dan later becomes associated with idolatry (Judg 18; 1 Kgs 12:29) and Dan's name is notably absent from the 144,000 list in Revelation 7.</p>",
    "39": "<p><strong>peqoudeihem lematteh Dan shnayim veshish'im elef vesheva me'ot</strong>: 'those enrolled of the tribe of Dan: 62,700.' Dan's count is substantial. The northern camp total (Dan + Asher + Naphtali): 62,700 + 41,500 + 53,400 = 157,600.</p>",
    "40": "<p><strong>livnei Asher</strong>: for Asher. Asher (son of Zilpah, Leah's maid) is flanking tribe in the northern/rear camp. The blessing of Asher (Gen 49:20: 'Asher's food shall be rich; he shall yield royal delicacies') and Moses's blessing (Deut 33:24-25: 'most blessed of sons is Asher... as your days, so is your strength') mark him as prosperous. Anna the prophetess who greeted the infant Jesus at the temple was from Asher (Luke 2:36).</p>",
    "41": "<p><strong>peqoudeihem lematteh Asher echad ve-arba'im elef vachamesh me'ot</strong>: 'those enrolled of the tribe of Asher: 41,500.' Asher's count.</p>",
    "42": "<p><strong>livnei Naftali</strong>: for Naphtali. Naphtali (son of Bilhah, Rachel's maid) completes the rear camp group. Naphtali's territory (northern Galilee around the Sea of Galilee) is the region where Jesus conducted the majority of his ministry. Isaiah's prophecy (9:1-2: 'the land of Zebulun and Naphtali... a great light') is cited at the beginning of Jesus's Galilean ministry (Matt 4:13-16).</p>",
    "43": "<p><strong>peqoudeihem lematteh Naftali shloshah vachamishim elef ve-arba me'ot</strong>: 'those enrolled of the tribe of Naphtali: 53,400.' The formula closes the twelve-tribe census. <em>Peqoudeihem</em> (those enrolled/numbered): the <em>paqad</em> verb's participial form; each tribal entry climaxes with this enrollment count.</p>",
    "44": "<p><strong>eleh hapekudim asher pakad Moshe ve-Aharon</strong>: 'these are those who were enrolled, whom Moses and Aaron enrolled.' <em>Hapekudim... pakad</em>: the <em>paqad</em> cognate construction (enrolled / who enrolled) emphasizes the divine-authorized character of the count. <em>Venit nesiei Yisrael</em> (and the princes of Israel with them) — the 12 tribal leaders co-authorized the census.</p>",
    "45": "<p><strong>vayihyu kol-pekudei vnei-Yisrael leveit avotam mikol-anshei Yisrael</strong>: 'all those enrolled of the people of Israel, by their fathers' houses, from twenty years old and upward, all able to go to war in Israel.' The census is summarized before the total: enumerated by <em>beit av</em> (father's house), by age (20+), by military qualification. The threefold specification mirrors v2's counting method — the census is internally consistent.</p>",
    "46": "<p><strong>vayihyu kol-hapekudim shesh-me'ot alef ushelosheth alafim wachamesh me'ot vachamishim</strong>: 'all those enrolled were 603,550.' The grand total — <em>shesh-me'ot elef</em> (six hundred thousand) + <em>shelosheth alafim</em> (three thousand) + <em>chamesh me'ot vachamishim</em> (550). This figure is closely tied to Exod 12:37 ('about 600,000 men on foot') and Exod 38:26 (603,550 in the half-shekel census). The <em>elef</em> debate: if some <em>alafim</em> are military units rather than thousands, the total becomes dramatically smaller. The scholarly debate remains unresolved; the text's own internal consistency suggests the numbers are meant as literal — an army of roughly 600,000.</p>",
    "47": "<p><strong>vehaleviim lematteh avotam lo hutpakedu betocham</strong>: 'but the Levites were not enrolled among them by their tribal affiliation.' The Levite exemption from the military census is the pivot of the chapter. <em>Lo hutpakedu</em> (they were not enrolled/numbered) — the Levites are <em>not paqad'd</em> in this census. They will be numbered separately (Num 3-4) for a different purpose: not warfare but tabernacle service. The exemption distinguishes warrior-Israel from servant-Israel (the Levites).</p>",
    "48": "<p><strong>ki diber YHWH el-Moshe lemor</strong>: 'for YHWH spoke to Moses, saying' — the divine instruction explaining the Levite exception. The census exception is not administrative but theological: Levites belong to a different category of service than the military tribes. The <em>ki</em> (because/for) signals the causal basis: it is YHWH's word, not human policy, that sets apart the Levites.</p>",
    "49": "<p><strong>ach et matteh Levi lo tifkod</strong>: 'only the tribe of Levi you shall not number.' <em>Ach</em> (only/but) — the contrastive particle marking the single exception to the universal census. Levi is the one tribe exempt from military enrollment, set apart for tabernacle ministry. The theological point is significant: the tribe that serves at the altar stands outside the military count — a division of labor built into the covenant community's structure.</p>",
    "50": "<p><strong>ve-atah haf ket et-haleviyim al mishkan ha'edut</strong>: 'but appoint the Levites over the tabernacle of the testimony.' <em>Haf ket</em> (appoint/set): the Levites are not exempt from service but reassigned from military to sanctuary service. <em>Mishkan ha'edut</em> (tabernacle of the testimony) — the <em>edut</em> (testimony, witness) refers to the tablets of the law in the ark; the tabernacle is defined by what it houses: the divine testimony. Levites transport, assemble, and guard the tabernacle and all its vessels.</p>",
    "51": "<p><strong>veha'zar hakorev yumat</strong>: 'and the stranger [non-Levite] who draws near shall be put to death.' <em>Zar</em> (stranger/unauthorized person) — not a foreigner but any Israelite who is not a Levite; <em>zar</em> in the priestly context means 'unauthorized' (the wrong person approaching the wrong thing). This is not hostility toward outsiders but the holiness boundary: approaching the sanctuary without proper authorization is deadly because the sanctuary is YHWH's holy space. The barrier between ordinary Israel and the sanctuary is encoded in law.</p>",
    "52": "<p><strong>vachanah bnei Yisrael ish al-machanehu ve'ish al-diglo letzivotam</strong>: 'the people of Israel shall camp each by his own camp and each by his own standard according to their companies.' <em>Machaneh</em> (camp) — the military-settlement term; the camp of Israel is an organized military encampment. <em>Degel</em> (standard/banner) — introduced here for the first time; the tribal grouping flag. <em>Letzivotam</em> (by their armies/companies) — <em>tzava</em> again.</p>",
    "53": "<p><strong>vehaleviim yachanu saviv lemishkan ha'edut</strong>: 'but the Levites shall camp around the tabernacle of the testimony.' The spatial arrangement: tribes camp in their four-directional groups; Levites surround the tabernacle in the center. <em>Ve-lo yihyeh ketzef</em> (that there be no wrath) — the Levite encirclement is a protective buffer preventing unauthorized access by non-Levites. The wrath (<em>ketzef</em>) that would fall on Israel if non-Levites approached is deflected by the Levite cordon.</p>",
    "54": "<p><strong>va-ya'asu bnei Yisrael kekol asher tzivah YHWH et-Moshe ken asu</strong>: 'and the people of Israel did according to all that YHWH commanded Moses; so they did.' The closing obedience formula: <em>ka'asher tzivah... ken asu</em> (as commanded... so they did). Numbers 1 ends in full covenant compliance. The formula of obedience at chapter-end is a Numbers pattern that will be tested and broken in the wilderness murmurings ahead. Here, at the outset, Israel is fully obedient.</p>"
  },
  "2": {
    "1": "<p><strong>vayedaber YHWH el-Moshe ve'el-Aharon lemor</strong>: YHWH speaks to both Moses and Aaron — the census (ch1) was addressed to Moses alone; the camp arrangement is addressed to both, since both priestly and civil leadership determine the spatial arrangement of the holy community around the sanctuary.</p>",
    "2": "<p><strong>ish al-diglo be'otot leveit avotam</strong>: 'each man by his own standard [<em>degel</em>], with the signs [<em>otot</em>] of their fathers' houses.' <em>Degel</em> (standard/banner) — the large tribal-group flag; <em>ot</em> (sign/standard) — the smaller clan-level banner. The two-level flag system mirrors the two-level organizational structure of the census (<em>mishpacha</em> and <em>beit av</em>). <em>Mineged saviv le'ohel mo'ed yachanu</em>: 'they shall camp facing, from all sides, the tent of meeting' — the tabernacle is the center; all four camp-directions face inward toward it. YHWH's dwelling is the centripetal force of Israel's entire spatial organization.</p>",
    "3": "<p><strong>vehaconim kidmah mizracha degel machaneh Yehudah letzivotam</strong>: 'on the east side toward the sunrise shall be the standard of the camp of Judah by their companies.' <em>Kidmah mizracha</em> (eastward, toward the sunrise) — the most honorable position: the side of sunrise, the direction of the divine presence (the east-facing tabernacle entrance). Judah receives the vanguard position — first in the order of march, first in the direction of first light. This primacy of Judah (the messianic tribe) in the camp arrangement mirrors Jacob's deathbed blessing (Gen 49:8-12).</p>",
    "4": "<p><strong>utzva'o ufekudeihem arba'ah veshiv'im elef veshesh me'ot</strong>: 'his company as enrolled: 74,600' — Judah's count repeated from ch1. The repetition confirms: the census and camp arrangement are a single coordinated system. <em>Tzava</em> (company/army) — each tribal group is also an <em>tzava</em>, an army division in the marching order.</p>",
    "5": "<p><strong>vehachoneh alav matteh Yissachar</strong>: 'and camping next to him shall be the tribe of Issachar.' <em>Alav</em> (next to him/alongside him) — the flanking position; Issachar and Zebulun flank Judah in the eastern camp. The three-tribe groupings of the four camps create four mini-armies, each under a lead tribe.</p>",
    "6": "<p><strong>utzva'o ufekudav arba'ah vachamishim elef ve-arba me'ot</strong>: 'his company as enrolled: 54,400' — Issachar's count from ch1.</p>",
    "7": "<p><strong>matteh Zevulun</strong>: the tribe of Zebulun. Zebulun completes the eastern camp group. <em>Nafkei orach yam</em> is Jacob's blessing (Gen 49:13) — Zebulun's territory touches the sea; their later association with the Galilean coast region fulfills geographic destiny.</p>",
    "8": "<p><strong>utzva'o ufekudav shiv'ah vachamishim elef ve-arba me'ot</strong>: 'his company as enrolled: 57,400' — Zebulun's count.</p>",
    "9": "<p><strong>kol hapekudim lemachaneh Yehudah me'at shmonah veshmonim elef ve-arba me'ot letzivotam rishonah yis'u</strong>: 'all those enrolled of the camp of Judah: 186,400 by their companies. They shall set out first.' <em>Rishonah yis'u</em> (they shall set out/march first) — Judah leads the entire nation in the march. This vanguard position for Judah is the spatial enactment of the messianic promise: the scepter-tribe goes first, the royal lineage at the head of the covenant nation.</p>",
    "10": "<p><strong>degel machaneh Reuven teimana letzivotam</strong>: 'the standard of the camp of Reuben on the south side.' <em>Teiman</em> (south) — the second camp position. Despite being Jacob's firstborn, Reuben is assigned the secondary south position rather than the primary east. Reuben lost his primacy through the sin against Bilhah (Gen 35:22; 49:3-4: 'unstable as water, you shall not have preeminence'). The census/camp arrangement encodes the covenantal consequences of the patriarchal history.</p>",
    "11": "<p><strong>utzva'o ufekudav shisha ve-arba'im elef vachamesh me'ot</strong>: 'his company as enrolled: 46,500' — Reuben's count. Reuben's group (46,500 + 59,300 + 45,650 = 151,450) is the second-smallest camp contingent, after Ephraim's (108,100).</p>",
    "12": "<p><strong>vehachoneh alav matteh Shim'on</strong>: 'and camping next to him shall be the tribe of Simeon.' Simeon flanks Reuben in the southern camp. Jacob's dying words to Simeon and Levi were harsh (Gen 49:5-7: 'I will divide them in Jacob and scatter them in Israel'). Simeon's numbers will collapse by the second census (from 59,300 to 22,200), and the tribe is not mentioned in Moses's final blessing (Deut 33). Levi's scattering becomes priestly blessing; Simeon's scattering becomes tribal dissolution.</p>",
    "13": "<p><strong>utzva'o ufekudav tish'ah vachamishim elef ushlosh me'ot</strong>: 'his company as enrolled: 59,300' — Simeon's count.</p>",
    "14": "<p><strong>umatteh Gad</strong>: and the tribe of Gad. Gad rounds out the southern camp group with Reuben and Simeon. Gad's blessing (Gen 49:19: 'raiders shall raid him, but he shall raid at their heels') suggests a warrior tribe; Gad will later settle east of the Jordan (Num 32) and be known for swift warriors (1 Chr 12:8).</p>",
    "15": "<p><strong>utzva'o ufekudav chamisha vechamishim elef veshesh me'ot vachamishim</strong>: 'his company as enrolled: 45,650' — Gad's count.</p>",
    "16": "<p><strong>kol hapekudim lemachaneh Reuven echad vachamishim elef ve-arba me'ot vachamishim letzivotam ushniim yis'u</strong>: 'all those enrolled of the camp of Reuben: 151,450 by their companies. They shall set out second.' <em>Ushniim yis'u</em> (they shall set out second) — Reuben's camp marches after Judah. The march order (east first, south second, west third, north last) maps the camp onto a counter-clockwise rotation when viewed from above.</p>",
    "17": "<p><strong>venas'a ohel mo'ed machaneh haleviyim betoch hamachanot</strong>: 'then the tent of meeting shall set out, the camp of the Levites in the midst of the camps.' The tabernacle and its Levite carriers march in the center — between the two front camps (Judah, Reuben) and the two rear camps (Ephraim, Dan). The Levites are not a fighting unit but the center of the entire march. <em>Ka'asher yachanu ken yis'u</em>: 'as they camp, so they shall set out' — the marching formation exactly mirrors the camp arrangement. The holy center of Israel is always at the center, whether stationary or moving.</p>",
    "18": "<p><strong>degel machaneh Efrayim letzivotam yama</strong>: 'the standard of the camp of Ephraim on the west side.' <em>Yama</em> (westward, toward the sea) — the third camp position. Ephraim's western position may reflect the tribal territory Ephraim would receive in Canaan (central highlands, western-ish). The western camp groups the Joseph tribes (Ephraim and Manasseh) with Benjamin — the three sons closest to Joseph in the Jacob narrative.</p>",
    "19": "<p><strong>utzva'o ufekudav arba'ah vethlashim elef vachamesh me'ot</strong>: 'his company as enrolled: 40,500' — Ephraim's count.</p>",
    "20": "<p><strong>ve'alav matteh Menashe</strong>: 'and next to him the tribe of Manasseh.' Manasseh, despite seniority, is flanking rather than leading in the Joseph camp group — the Jacob blessing precedence (Ephraim over Manasseh, Gen 48) is encoded in the camp arrangement.</p>",
    "21": "<p><strong>utzva'o ufekudav shnayim uthlashim elef umayatayim</strong>: 'his company as enrolled: 32,200' — Manasseh's count, the smallest in the census.</p>",
    "22": "<p><strong>umatteh Binyamin</strong>: and the tribe of Benjamin. Benjamin joins the western camp with the Joseph tribes — his brothers by Rachel. Benjamin's physical closeness to the Joseph tribes in the patriarchal narrative (Benjamin = Rachel's second son, Joseph's full brother) is preserved in the camp arrangement. The brotherhood of full siblings is honored spatially.</p>",
    "23": "<p><strong>utzva'o ufekudav chamisha uthlashim elef ve-arba me'ot</strong>: 'his company as enrolled: 35,400' — Benjamin's count.</p>",
    "24": "<p><strong>kol hapekudim lemachaneh Efrayim shmona vethlashim elef ume'ah letzivotam vshlishim yis'u</strong>: 'all those enrolled of the camp of Ephraim: 108,100 by their companies. They shall set out third.' <em>Vshlishim yis'u</em> (they shall set out third). The western camp (108,100) is the smallest of the four camps — Rachel's descendants plus Benjamin. The two sons of Jacob's beloved Rachel (Joseph/Ephraim-Manasseh and Benjamin) lead the western camp that marches third.</p>",
    "25": "<p><strong>degel machaneh Dan tzafonah letzivotam</strong>: 'the standard of the camp of Dan on the north side.' <em>Tzafonah</em> (northward) — the fourth and last camp position. Dan leads the rear guard — the most rearward and exposed position. Dan's later association with idolatry and northern apostasy (Judg 17-18; 1 Kgs 12:29) may connect to this end-of-the-line position at the furthest remove from the tabernacle.</p>",
    "26": "<p><strong>utzva'o ufekudav shnayim veshish'im elef vesheva me'ot</strong>: 'his company as enrolled: 62,700' — Dan's count. Dan is the second-largest single tribe (after Judah).</p>",
    "27": "<p><strong>vehachoneh alav matteh Asher</strong>: 'and camping next to him the tribe of Asher.' Asher's prosperous blessing (Gen 49:20; Deut 33:24-25) and the tribe's later territory in the northern coastal plain. Anna the prophetess from Asher (Luke 2:36-38) is the only NT figure identified by Asher tribal membership.</p>",
    "28": "<p><strong>utzva'o ufekudav echad ve-arba'im elef vachamesh me'ot</strong>: 'his company as enrolled: 41,500' — Asher's count.</p>",
    "29": "<p><strong>umatteh Naftali</strong>: and the tribe of Naphtali, completing the northern rear-guard camp. Naphtali's blessing (Gen 49:21: 'a swift deer that yields beautiful fawns') and territory in upper Galilee (Sea of Galilee region) connect to the Galilean ministry of Jesus (Matt 4:13-16). The last camp group in the march contains the tribe whose land will be the first to see 'a great light.'</p>",
    "30": "<p><strong>utzva'o ufekudav shloshah vachamishim elef ve-arba me'ot</strong>: 'his company as enrolled: 53,400' — Naphtali's count.</p>",
    "31": "<p><strong>kol hapekudim lemachaneh Dan me'at vashiv'im vethlashim elef vashmona me'ot le'acharonah yis'u lediegleihem</strong>: 'all those enrolled of the camp of Dan: 157,600. They shall set out last, by their standards.' <em>Le'acharonah yis'u</em> (they shall set out last) — the rear guard. <em>Lediegleihem</em> (by their standards) — the closing phrase of the marching-order section; the <em>degel</em> system provides organizational identity even to those at the back.</p>",
    "32": "<p><strong>eleh pekudei vnei Yisrael leveit avotam</strong>: 'these are those enrolled of the people of Israel by their fathers' houses.' The census summary restates the organizing principle: <em>beit avot</em> (fathers' houses). The entire camp is structured on patriarchal lineage — each person knows their place in the spatial arrangement because they know their tribal ancestry.</p>",
    "33": "<p><strong>vehaleviyim lo hitpakedu betoch bnei Yisrael ka'asher tzivah YHWH et-Moshe</strong>: 'and the Levites were not enrolled among the people of Israel, as YHWH commanded Moses.' The Levite exemption from the twelve-tribe census is confirmed at the chapter's close. <em>Ka'asher tzivah YHWH</em> — as YHWH commanded: the exception is not an oversight but deliberate divine structuring. The Levites stand apart — spatially (at the center), functionally (sanctuary service), and statistically (not counted in the military census).</p>",
    "34": "<p><strong>va-ya'asu bnei Yisrael kekol asher tzivah YHWH et-Moshe ken chanu letiegleihem vachen nas'u ish lemishpechotav al-beit avotav</strong>: 'the people of Israel did according to all that YHWH commanded Moses. So they camped by their standards, and so they set out, each one by his clan, according to his father's house.' The closing obedience formula mirrors ch1:54. Both the census and the camp arrangement are completed in full obedience. <em>Ish lemishpechotav al-beit avotav</em> (each one by his clan, according to his father's house) — the final phrase returns to the organizing categories of ch1:2. Order, genealogy, and obedience characterize Israel at Sinai — before the wilderness failures begin.</p>"
  }
}

def main():
    c = load_comm('mkt-original', 'numbers')
    merge_comm(c, ORIGINAL)
    save_comm('mkt-original', 'numbers', c)
    print('Numbers 1-2 mkt-original written.')

if __name__ == '__main__':
    main()
